    elif "valueCodeableConcept" in latest_observation and latest_observation["valueCodeableConcept"] and "text" in latest_observation["valueCodeableConcept"]:
        latest_value = latest_observation["valueCodeableConcept"]["text"]

observation_record = None
observation_id = None

can_create = True
if not subject_reference:
