    elif resource.get('issued'):
        candidate_timestamp = resource.get('issued')
    elif resource.get('meta') and resource['meta'].get('lastUpdated'):
        candidate_timestamp = resource['meta'].get('lastUpdated')

    if candidate_timestamp is not None:
