    for entry in response['entry']:
        if entry and 'resource' in entry:
            resource = entry['resource']
            if resource and resource.get('resourceType') == 'Observation':
                observations.append(resource)

most_recent_observation = None
most_recent_time = None

for observation in observations:
    candidate_time = None
    if observation.get('effectiveDateTime'):
        candidate_time = observation.get('effectiveDateTime')
    elif observation.get('issued'):
        candidate_time = observation.get('issued')

    value_quantity = observation.get('valueQuantity')
    has_numeric_value = False
    if value_quantity and 'value' in value_quantity:
