            has_numeric_value = True

    if candidate_time and has_numeric_value:
        if most_recent_time is None or candidate_time > most_recent_time:
            most_recent_time = candidate_time
            most_recent_observation = observation

most_recent_value = None
most_recent_unit = None
observation_time = None
