        status_message = f"Most recent {lab_name} result for patient {patient_id} was {most_recent_value} {most_recent_unit} at {observation_time}, which is below the low threshold of {low_threshold}."
    else:
        status_message = f"Most recent {lab_name} result for patient {patient_id} was {most_recent_value} {most_recent_unit} at {observation_time}, which is not below the low threshold of {low_threshold}."
else:
