        if "id" in service_request_resource and service_request_resource["id"]:
            service_request_id = service_request_resource["id"]

search_result = apis.fhir.get_observations_by_patient_and_code(
    patient=patient_identifier,
    code=lab_code
)

entries = []
if search_result and 'entry' in search_result and search_result['entry']:
    entries = search_result['entry']

observations = []

for entry in entries:
    resource = entry.get('resource', {})
    if resource.get('resourceType') != 'Observation':
        continue

    observation_date = resource.get('effectiveDateTime')
    if not observation_date:
        observation_date = resource.get('issued')

    code_text = ''
    code_data = resource.get('code', {})
    if code_data.get('text'):
        code_text = code_data.get('text')
    else:
        codings = code_data.get('coding', [])
        if codings:
            code_text = codings[0].get('display', '')

    value = None
    unit = ''
    if 'valueQuantity' in resource:
        value = resource['valueQuantity'].get('value')
        unit = resource['valueQuantity'].get('unit', '')
    elif 'valueString' in resource:
        value = resource.get('valueString')
    elif 'valueCodeableConcept' in resource:
        value_codings = resource['valueCodeableConcept'].get('coding', [])
        if value_codings:
            value = value_codings[0].get('display') or value_codings[0].get('code')
        else:
            value = resource['valueCodeableConcept'].get('text')

    normalized = {
        'id': resource.get('id'),
        'status': resource.get('status'),
        'code': lab_code,
        'display': code_text,
        'date': observation_date,
        'value': value,
        'unit': unit,
        'resource': resource
